// Time:  O(n)
// Space: O(1)

class Solution {
public:
    int minOperations(vector<string>& logs) {
        int result = 0;
        for (const auto& log: logs) {
            if (log == "../") {
                if (result > 0) {
                    --result;
                }
            } else if (log != "./") {
                ++result;
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def minOperations(self, logs):
        """
        :type logs: List[str]
        :rtype: int
        """
        result = 0
        for log in logs:
            if log == "../":
                if result > 0:
                    result -= 1
            elif log != "./":
                result += 1
        return result
